import React, { useState, useEffect, useCallback } from 'react';
import { 
  Box, 
  Paper,
  Alert,
  Divider
} from '@mui/material';
import { Info as InfoIcon } from '@mui/icons-material';
import FAWTypography from '../../FAWTypography';
import FAWInput from '../../FAWInput';
import FAWSelect from '../../FAWSelect';
import FAWDropdown from '../../FAWDropdown';
import FAWCheckbox from '../../FAWCheckbox';
import FAWButton from '../../FAWButton';
import FAWDrawer from '../../FAWDrawer';
import FAWToast from '../../FAWToast';
import FAWLoader from '../../FAWLoader';
import FAWErrorBoundary from '../../errorHandling/FAWErrorBoundary';
import FAWAlert from '../../FAWAlert';
import { colors } from '../../../../utils/designTokens';

/**
 * Helper function to convert hex color to rgba
 */
const hexToRgba = (hex, alpha = 1) => {
  if (!hex) return null;
  const cleanHex = hex.replace('#', '');
  const r = parseInt(cleanHex.substr(0, 2), 16);
  const g = parseInt(cleanHex.substr(2, 2), 16);
  const b = parseInt(cleanHex.substr(4, 2), 16);
  return `rgba(${r}, ${g}, ${b}, ${alpha})`;
};

/**
 * RefCode Attribute Form Component
 * Handles Add/Edit operations for RefCode attributes
 */
const RefCodeAttributeForm = ({ 
  isOpen,
  onClose,
  onSuccess,
  editingAttribute = null,
  domain,
  code,
  agencyId
}) => {
  // Form state
  const [formData, setFormData] = useState({
    AttributeName: '',
    AttributeValue: '',
    FromRefCode: false,
    AttributeValueDomain: '',
    AttributeValueCode: ''
  });
  const [loading, setLoading] = useState(false);
  const [initializing, setInitializing] = useState(false);
  const [error, setError] = useState(null);
  const [attributeNames, setAttributeNames] = useState([]);
  const [isAttrNameEditable, setIsAttrNameEditable] = useState(true);
  const [nameValidationError, setNameValidationError] = useState(null);
  const [refDomains, setRefDomains] = useState([]);
  const [refCodes, setRefCodes] = useState([]);
  const [codesLoading, setCodesLoading] = useState(false);

  // Toast state
  const [toast, setToast] = useState({ open: false, message: '', type: 'info' });

  // Initialize form data and fetch form metadata via JSON endpoints
  useEffect(() => {
    let cancelled = false;
    const init = async () => {
      setError(null);
      if (!isOpen) return;
      setInitializing(true);
      try {
        const endpoint = editingAttribute ? '/RefCodeAttribute/EditRefCodeAttributeJson' : '/RefCodeAttribute/AddRefCodeAttributeJson';
        const payload = editingAttribute ? {
          domain,
          code,
          agencyId,
          attrName: editingAttribute.AttributeName,
          attrValue: editingAttribute.AttributeValue
        } : { domain, code, agencyId };

        const response = await fetch(endpoint, {
          method: 'POST',
          headers: {
            'Content-Type': 'application/json',
            'RequestVerificationToken': getCsrfToken()
          },
          body: JSON.stringify(payload)
        });

        if (cancelled) return;

        if (response.ok) {
          const json = await response.json();
          // Store attribute names and editability
          // Backend sends value-label pairs with disabled flag: [{ value: "", label: "-- SELECT --", disabled: false }, { value: "Attr1", label: "Attr1 (Desc)", disabled: true }, ...]
          const names = Array.isArray(json?.attributeNames) ? json.attributeNames : [];
          // Filter out disabled options (attributes already assigned to this code) for add mode
          // For edit mode (isAttrNameEditable === false), the dropdown is disabled anyway
          const filteredNames = names.filter(name => !name?.disabled);
          setAttributeNames(filteredNames.map(name => {
            // Ensure we always have string values, not objects
            const value = name?.value != null ? String(name.value) : '';
            const label = name?.label != null ? String(name.label) : (name?.value != null ? String(name.value) : '');
            return {
              value: value,
              label: label
            };
          }));
          setIsAttrNameEditable(json?.isAttrNameEditable ?? true);
          
          // Initialize refDomains and refCodes if provided
          if (json?.refDomains && Array.isArray(json.refDomains) && json.refDomains.length > 0) {
            setRefDomains(json.refDomains.map(d => ({ value: String(d.value ?? ''), label: String(d.label ?? '') })));
          }
          if (json?.refCodes && Array.isArray(json.refCodes) && json.refCodes.length > 0) {
            setRefCodes(json.refCodes.map(c => ({ value: String(c.value ?? ''), label: String(c.label ?? '') })));
          }
          
          // Initialize fields from payload and JSON
          if (editingAttribute) {
            setFormData({
              AttributeName: json?.attributeName ?? editingAttribute.AttributeName ?? '',
              AttributeValue: json?.attributeValue ?? editingAttribute.AttributeValue ?? '',
              FromRefCode: json?.fromRefCode ?? editingAttribute.FromRefCode ?? false,
              AttributeValueDomain: json?.attributeValueDomain ?? '',
              AttributeValueCode: json?.attributeValueCode ?? ''
            });
          } else {
            setFormData({
              AttributeName: json?.attributeName ?? '',
              AttributeValue: json?.attributeValue ?? '',
              FromRefCode: json?.fromRefCode ?? false,
              AttributeValueDomain: json?.attributeValueDomain ?? '',
              AttributeValueCode: json?.attributeValueCode ?? ''
            });
          }
        } else {
          // fallback init without metadata
          if (editingAttribute) {
            setFormData({
              AttributeName: editingAttribute.AttributeName || '',
              AttributeValue: editingAttribute.AttributeValue || '',
              FromRefCode: editingAttribute.FromRefCode || false,
              AttributeValueDomain: '',
              AttributeValueCode: ''
            });
          } else {
            setFormData({
              AttributeName: '',
              AttributeValue: '',
              FromRefCode: false,
              AttributeValueDomain: '',
              AttributeValueCode: ''
            });
          }
        }
      } catch (e) {
        // fallback init on error
        if (editingAttribute) {
          setFormData({
            AttributeName: editingAttribute.AttributeName || '',
            AttributeValue: editingAttribute.AttributeValue || '',
            FromRefCode: editingAttribute.FromRefCode || false,
            AttributeValueDomain: '',
            AttributeValueCode: ''
          });
        } else {
          setFormData({
            AttributeName: '',
            AttributeValue: '',
            FromRefCode: false,
            AttributeValueDomain: '',
            AttributeValueCode: ''
          });
        }
      } finally {
        if (!cancelled) setInitializing(false);
      }
    };
    init();
    return () => { cancelled = true; };
  }, [editingAttribute, isOpen, domain, code, agencyId, getCsrfToken]);


  // Helper function to get CSRF token
  const getCsrfToken = useCallback(() => {
    const token = document.querySelector('input[name="__RequestVerificationToken"]')?.value;
    return token;
  }, []);


  // Handle form field changes
  const handleFieldChange = useCallback((field, value) => {
    setFormData(prev => ({
      ...prev,
      [field]: value
    }));
  }, []);

  // Handle attribute name change with validation
  const handleAttributeNameChange = useCallback(async (selectedOption) => {
    // Handle null/undefined selection (when cleared)
    if (!selectedOption || !selectedOption.value) {
      handleFieldChange('AttributeName', '');
      setNameValidationError('Attribute Name is required');
      return;
    }
    
    const attrName = selectedOption.value;
    handleFieldChange('AttributeName', attrName);
    
    // Validate that a valid attribute name is selected (not empty, not placeholder)
    if (!attrName || attrName.trim() === '' || attrName === '-- SELECT --') {
      setNameValidationError('Attribute Name is required');
      return;
    }
    
    setNameValidationError(null);

    if (!domain || !code) return;

    try {
      const response = await fetch('/RefCodeAttribute/CheckUniqueName', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'RequestVerificationToken': getCsrfToken()
        },
        body: JSON.stringify({ domain, code, agencyId, attrName })
      });

      if (response.ok) {
        const json = await response.json();
        if (!json.isValid) {
          setNameValidationError(json.message || 'Attribute name is not valid');
        }
      }
    } catch (error) {
      console.error('Error validating attribute name:', error);
    }
  }, [domain, code, agencyId, getCsrfToken, handleFieldChange]);

  // Handle FromRefCode toggle
  const handleFromRefCodeChange = useCallback(async (checked) => {
    setFormData(prev => ({ ...prev, FromRefCode: checked }));
    setNameValidationError(null);

    if (!checked) {
      setRefDomains([]);
      setRefCodes([]);
      setFormData(prev => ({ ...prev, AttributeValueDomain: '', AttributeValueCode: '', AttributeValue: '' }));
      return;
    }

    try {
      const response = await fetch('/RefCodeAttribute/ChangeAttributeSourceJson', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'RequestVerificationToken': getCsrfToken()
        },
        body: JSON.stringify({ domain, code, agencyId, fromRefCode: checked })
      });

      if (response.ok) {
        const json = await response.json();
        const domains = Array.isArray(json?.refDomains) ? json.refDomains : [];
        setRefDomains(domains.map(d => ({ value: String(d.value ?? ''), label: String(d.label ?? '') })));
        setRefCodes([]);
        setFormData(prev => ({ ...prev, AttributeValueDomain: '', AttributeValueCode: '', AttributeValue: '' }));
      }
    } catch (error) {
      console.error('Error loading ref domains:', error);
    }
  }, [domain, code, agencyId, getCsrfToken]);

  // Handle attribute value domain change
  const handleAttributeValueDomainChange = useCallback(async (selectedOption) => {
    const newDomain = selectedOption?.value || '';
    handleFieldChange('AttributeValueDomain', newDomain);
    setRefCodes([]);
    setFormData(prev => ({ ...prev, AttributeValueCode: '', AttributeValue: '' }));

    if (!newDomain) return;

    setCodesLoading(true);
    try {
      const response = await fetch('/RefCodeAttribute/GetAttributeValueRefCodesJson', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'RequestVerificationToken': getCsrfToken()
        },
        body: JSON.stringify({ newAttrDomain: newDomain, agencyId })
      });

      if (response.ok) {
        const json = await response.json();
        const codes = Array.isArray(json?.refCodes) ? json.refCodes : [];
        setRefCodes(codes.map(c => ({ value: String(c.value ?? ''), label: String(c.label ?? '') })));
      }
    } catch (error) {
      console.error('Error loading ref codes:', error);
    } finally {
      setCodesLoading(false);
    }
  }, [agencyId, getCsrfToken, handleFieldChange]);

  // Handle attribute value code change
  const handleAttributeValueCodeChange = useCallback((selectedOption) => {
    const codeValue = selectedOption?.value || '';
    handleFieldChange('AttributeValueCode', codeValue);
    handleFieldChange('AttributeValue', codeValue);
  }, [handleFieldChange]);

  // Handle form submission
  const handleSubmit = useCallback(async (e) => {
    if (e && typeof e.preventDefault === 'function') {
      e.preventDefault();
    }
    setLoading(true);
    setError(null);

    try {
      // Validate form - set nameValidationError to show under the field
      if (!formData.AttributeName.trim()) {
        setNameValidationError('Attribute Name is required');
        setLoading(false);
        return;
      }

      // Determine the actual attribute value to save
      let attrValueToSave = formData.AttributeValue.trim();
      
      // Validate attribute value based on FromRefCode selection
      if (formData.FromRefCode) {
        // When FromRefCode is true, ensure Domain and Code are selected
        if (!formData.AttributeValueDomain || !formData.AttributeValueDomain.trim()) {
          setError('Domain is required when using RefCode');
          setLoading(false);
          return;
        }
        if (!formData.AttributeValueCode || !formData.AttributeValueCode.trim()) {
          setError('Code is required when using RefCode');
          setLoading(false);
          return;
        }
        // Use the selected code value as the attribute value
        attrValueToSave = formData.AttributeValueCode.trim();
      } else {
        // When FromRefCode is false, ensure text value is provided
        if (!formData.AttributeValue || !formData.AttributeValue.trim()) {
          setError('Attribute Value is required');
          setLoading(false);
          return;
        }
        attrValueToSave = formData.AttributeValue.trim();
      }

      // Final check for AttributeValue
      if (!attrValueToSave) {
        setError('Attribute Value is required');
        setLoading(false);
        return;
      }

      // Check for validation errors - don't set general error, let it show under the field
      if (nameValidationError) {
        setLoading(false);
        return;
      }

      // Submit to server - JSON save endpoint
      const endpoint = '/RefCodeAttribute/AddOrUpdateRefCodeAttributeJson';
      const payload = {
        domain: domain,
        code: code,
        agencyId,
        attrName: formData.AttributeName.trim(),
        attrValue: attrValueToSave
      };
      const response = await fetch(endpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'RequestVerificationToken': getCsrfToken()
        },
        body: JSON.stringify(payload)
      });
      
      if (response.ok) {
        const result = await response.json();
        if (result.success) {
          setToast({
            open: true,
            message: editingAttribute ? 'Attribute updated successfully' : 'Attribute added successfully',
            type: 'success'
          });
          onSuccess && onSuccess(result);
          onClose && onClose();
        } else {
          setError(result.message || 'Operation failed');
        }
      } else {
        setError('Failed to save attribute');
      }
      setLoading(false);
    } catch (error) {
      console.error('Error saving attribute:', error);
      setError('Failed to save attribute');
      setLoading(false);
    }
  }, [formData, domain, code, agencyId, editingAttribute, onSuccess, onClose, getCsrfToken, nameValidationError]);

  // Handle cancel
  const handleCancel = useCallback(() => {
    setFormData({ 
      AttributeName: '', 
      AttributeValue: '', 
      FromRefCode: false, 
      AttributeValueDomain: '', 
      AttributeValueCode: '' 
    });
    setError(null);
    setNameValidationError(null);
    setRefDomains([]);
    setRefCodes([]);
    onClose && onClose();
  }, [onClose]);

  return (
    <FAWErrorBoundary>
      <FAWDrawer
        open={isOpen}
        onClose={handleCancel}
        title={editingAttribute ? "Edit Attribute" : "Add Attribute"}
        subtitle="Attachment"
        anchor="right"
        width={400}
        actions={[
          {
            text: 'Cancel',
            variant: 'outlined',
            color: 'inherit',
            onClick: handleCancel,
            disabled: loading || initializing
          },
          {
            text: loading ? 'Saving...' : (editingAttribute ? 'Update' : 'Add'),
            variant: 'contained',
            color: 'primary',
            onClick: handleSubmit,
            disabled: loading || initializing || !!nameValidationError
          }
        ]}
      >
        <Box sx={{ pt: 1, px: 3 }}>
          {initializing ? (
            <Box sx={{ display: 'flex', justifyContent: 'center', py: 4 }}>
              <FAWLoader label="Loading..." size={32} inline={false} />
            </Box>
          ) : loading ? (
            <Box sx={{ display: 'flex', justifyContent: 'center', py: 4 }}>
              <FAWLoader label="Saving attribute..." size={32} inline={false} />
            </Box>
          ) : (
            <form onSubmit={handleSubmit}>
              {/* Attribute Name */}
              <Box sx={{ mb: 1 }}>
                {isAttrNameEditable ? (
                  <>
                    <FAWDropdown
                      label="Attribute Name"
                      required
                      options={attributeNames}
                      value={formData.AttributeName}
                      onChange={handleAttributeNameChange}
                      placeholder="Choose an option"
                      fullWidth
                      disabled={loading || initializing}
                      labelSx={{ fontSize: '14px', fontWeight: 500 }}
                    />
                    {/* Show message when no attribute names are available (all already assigned or none defined) */}
                    {!loading && !initializing && attributeNames.filter(a => a.value !== '').length === 0 && (
                      <Alert severity="warning" sx={{ mt: 1, mb: 0 }}>
                        No attribute names are available. All defined attributes may have already been assigned to this code, or no attributes are defined for this domain.
                      </Alert>
                    )}
                  </>
                ) : (
                  <FAWInput
                    label="Attribute Name"
                    required
                    value={formData.AttributeName}
                    placeholder="Attribute name"
                    fullWidth
                    disabled={true}
                    readOnly
                    labelSx={{ fontSize: '14px', fontWeight: 500 }}
                  />
                )}
                {nameValidationError && (
                  <Alert severity="error" sx={{ mt: 1, mb: 0 }}>
                    {nameValidationError}
                  </Alert>
                )}
              </Box>

              {/* FromRefCode Checkbox */}
              <Box sx={{ mb: 1 }}>
                <FAWCheckbox
                  label="From RefCode?"
                  checked={formData.FromRefCode}
                  onChange={(e) => handleFromRefCodeChange(e.target.checked)}
                  disabled={loading || initializing}
                />
              </Box>

              {/* Attribute Value */}
              <Box sx={{ mb: 2 }}>
                {formData.FromRefCode ? (
                  <>
                    <FAWInput
                      label="Attribute Value"
                      required
                      value={formData.AttributeValue}
                      placeholder="Attribute value"
                      fullWidth
                      disabled={true}
                      readOnly
                      labelSx={{ fontSize: '14px', fontWeight: 500, }}
                      sx={{
                        '& .MuiOutlinedInput-input.Mui-disabled': {
                          cursor: 'not-allowed',
                        },
                      }}
                    />

                    <FAWAlert 
                      severity="info" 
                      sx={{ mt: 1, mb: 2, fontSize: '16px' }} 
                      message="This value will be populated as you choose from the Code dropdown menu." 
                    />

                    {/* Domain Dropdown (only when FromRefCode is checked) */}
                    <Box sx={{ mb: 1 }}>
                      <FAWDropdown
                        label="Domain"
                        options={refDomains}
                        value={formData.AttributeValueDomain}
                        onChange={handleAttributeValueDomainChange}
                        placeholder="Choose an option"
                        fullWidth
                        disabled={loading || initializing}
                        labelSx={{ fontSize: '14px', fontWeight: 500 }}
                      />
                    </Box>

                    {/* Code Dropdown (only when FromRefCode is checked) */}
                    <Box sx={{ mb: 1 }}>
                      <FAWDropdown
                        label="Code"
                        options={refCodes}
                        value={formData.AttributeValueCode}
                        onChange={handleAttributeValueCodeChange}
                        placeholder="Choose an option"
                        fullWidth
                        disabled={!formData.AttributeValueDomain || loading || initializing || codesLoading}
                        loading={codesLoading}
                        labelSx={{ fontSize: '14px', fontWeight: 500 }}
                      />
                    </Box>
                  </>
                ) : (
                  <FAWInput
                    label="Attribute Value"
                    required
                    value={formData.AttributeValue}
                    onChange={(e) => handleFieldChange('AttributeValue', e.target.value)}
                    placeholder="Enter attribute value"
                    fullWidth
                    disabled={loading || initializing}
                    labelSx={{ fontSize: '14px', fontWeight: 500 }}
                  />
                )}
              </Box>

              {error && !nameValidationError && (
                <Alert severity="error" sx={{ mb: 2 }}>
                  {error}
                </Alert>
              )}
            </form>
          )}
        </Box>

        {/* Toast Notifications */}
        <FAWToast
          open={toast.open}
          message={toast.message}
          type={toast.type}
          onClose={() => setToast(prev => ({ ...prev, open: false }))}
        />
      </FAWDrawer>
    </FAWErrorBoundary>
  );
};

export default RefCodeAttributeForm;
