import React from "react";
import { Box, Typography, Button, Alert } from "@mui/material";
import { colors } from "../../../utils/designTokens";

class FAWErrorBoundary extends React.Component {
  constructor(props) {
    super(props);
    this.state = { hasError: false, error: null, errorInfo: null };
  }

  static getDerivedStateFromError(error) {
    // Update state so the next render will show the fallback UI
    return { hasError: true };
  }

  componentDidCatch(error, errorInfo) {
    // Log the error to console or error reporting service
    console.error('FAWErrorBoundary caught an error:', error, errorInfo);
    
    this.setState({
      error: error,
      errorInfo: errorInfo
    });

    // Optional: Send error to logging service
    if (this.props.onError) {
      this.props.onError(error, errorInfo);
    }
  }

  handleRetry = () => {
    this.setState({ hasError: false, error: null, errorInfo: null });
  };

  render() {
    if (this.state.hasError) {
      // Custom fallback UI
      if (this.props.fallback) {
        return this.props.fallback;
      }

      // Default fallback UI
      return (
        <Box
          sx={{
            padding: 3,
            border: `1px solid ${colors.ui.border.static}`,
            borderRadius: 1,
            backgroundColor: colors.background.secondary,
            textAlign: 'center',
            maxWidth: 600,
            margin: '20px auto'
          }}
        >
          <Alert severity="error" sx={{ marginBottom: 2 }}>
            <Typography variant="h6" gutterBottom>
              {this.props.title || 'Something went wrong'}
            </Typography>
            <Typography variant="body2" color="text.secondary" gutterBottom>
              {this.props.message || 'An unexpected error occurred while rendering this component.'}
            </Typography>
          </Alert>

          {this.props.showDetails && this.state.error && (
            <Box sx={{ textAlign: 'left', marginBottom: 2 }}>
              <Typography variant="subtitle2" gutterBottom>
                Error Details:
              </Typography>
              <Box
                component="pre"
                sx={{
                  fontSize: '0.75rem',
                  backgroundColor: colors.background.secondary,
                  padding: 1,
                  borderRadius: 1,
                  overflow: 'auto',
                  maxHeight: 200
                }}
              >
                {this.state.error.toString()}
                {this.state.errorInfo && this.state.errorInfo.componentStack}
              </Box>
            </Box>
          )}

          <Box sx={{ display: 'flex', gap: 1, justifyContent: 'center' }}>
            <Button variant="contained" onClick={this.handleRetry}>
              Try Again
            </Button>
            {this.props.onReportError && (
              <Button variant="outlined" onClick={() => this.props.onReportError(this.state.error)}>
                Report Issue
              </Button>
            )}
          </Box>
        </Box>
      );
    }

    return this.props.children;
  }
}

export default FAWErrorBoundary;


