import React from 'react';
import { Dialog, DialogTitle, DialogContent, DialogActions, Button, Box, IconButton } from '@mui/material';
import WarningIcon from '@mui/icons-material/Warning';
import InfoIcon from '@mui/icons-material/Info';
import CloseIcon from '@mui/icons-material/Close';
import FAWTypography from './FAWTypography';
import { colors } from "../../utils/designTokens";

/**
 * FAWConfirmationDialog - A reusable confirmation dialog component
 * Props:
 *   open: boolean (controls visibility)
 *   title: string (dialog title)
 *   message: string (confirmation message)
 *   onConfirm: function (called when user confirms)
 *   onCancel: function (called when user cancels)
 *   confirmText: string (text for confirm button, default: "Yes")
 *   cancelText: string (text for cancel button, default: "No")
 *   severity: 'warning' | 'info' | 'error' (icon and color, default: 'warning')
 *   maxWidth: string (dialog max width, default: 'sm')
 *   showCloseButton: boolean (whether to show close button in title, default: false)
 */
const FAWConfirmationDialog = ({
  open = false,
  title = 'Confirm Action',
  message = 'Are you sure?',
  onConfirm,
  onCancel,
  confirmText = 'Yes',
  cancelText = 'No',
  severity = 'warning',
  maxWidth = 'sm',
  showCloseButton = false,
  ...props
}) => {
  const getIcon = () => {
    switch (severity) {
      case 'error':
        return <WarningIcon color="error" sx={{ fontSize: 40 }} />;
      case 'info':
        return <InfoIcon color="info" sx={{ fontSize: 40 }} />;
      case 'warning':
      default:
        return <WarningIcon color="warning" sx={{ fontSize: 40 }} />;
    }
  };

  const getConfirmButtonColor = () => {
    switch (severity) {
      case 'error':
        return 'error';
      case 'info':
        return 'primary';
      case 'warning':
      default:
        return 'warning';
    }
  };

  return (
    <Dialog 
      open={open} 
      onClose={onCancel} 
      maxWidth={maxWidth} 
      fullWidth
      {...props}
    >
      <DialogTitle sx={{ 
        display: 'flex', 
        justifyContent: 'space-between', 
        alignItems: 'center',
        paddingLeft: '24px',
        paddingRight: '24px',
        pb: 1
      }}>
        <FAWTypography variant="h6" sx={{ fontWeight: 600 }}>
          {title}
        </FAWTypography>
        {showCloseButton && (
          <IconButton
            onClick={onCancel}
            size="small"
            sx={{ color: 'text.secondary' }}
          >
            <CloseIcon />
          </IconButton>
        )}
      </DialogTitle>
      
      <DialogContent>
        <FAWTypography variant="body1" sx={{ mt: 1, textAlign: 'left' }}>
          {message}
        </FAWTypography>
      </DialogContent>
      
      <DialogActions sx={{ p: 3, justifyContent: 'space-between', gap: 2 }}>
        <Button
          onClick={onCancel}
          variant="outlined"
          color="inherit"
          sx={{ minWidth: 100 }}
        >
          {cancelText || 'Cancel'}
        </Button>
        <Button
          onClick={onConfirm}
          variant="contained"
          color={getConfirmButtonColor()}
          sx={{ 
            minWidth: 100,
            ...(severity === 'error' && {
              backgroundColor: colors.status.error,
              color: colors.type.inverse,
              '&:hover': {
                backgroundColor: colors.status.error + 'dd'
              },
              '&:disabled': {
                backgroundColor: colors.status.error + '80',
                color: colors.type.inverse
              }
            })
          }}
        >
          {confirmText || 'Confirm'}
        </Button>
      </DialogActions>
    </Dialog>
  );
};

export default FAWConfirmationDialog;
